+{
+  ros::init(argc, argv, "web_video_server");
+
+  ros::NodeHandle nh;
+  ros::NodeHandle private_nh("~");
+
+  web_video_server::WebVideoServer server(nh, private_nh);
+  server.spin();
+
+  return (0);
+}
